import akka.actor.{Actor, ActorLogging, Props}

class AccountBalanceManager extends Actor with ActorLogging {
  var balance = 0

  def receive = {
    case Deposit(amount) =>
      balance += amount
      log.info("Deposited {} to account", amount)
    case Withdrawal(amount) =>
      if (balance >= amount) {
        balance -= amount
        log.info("Withdrew {} from account", amount)
      } else {
        log.warning("Insufficient funds in account")
      }
  }
}